import{_ as a,o as s,a as i,ag as t}from"./chunks/framework.C2qfZH9T.js";const k=JSON.parse('{"title":"Cache Strategy","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/cache-strategy.md","filePath":"advanced/cache-strategy.md","lastUpdated":1773836520000}'),n={name:"advanced/cache-strategy.md"};function p(r,e,l,h,d,o){return s(),i("div",null,e[0]||(e[0]=[t(`<h1 id="cache-strategy" tabindex="-1">Cache Strategy <a class="header-anchor" href="#cache-strategy" aria-label="Permalink to &quot;Cache Strategy&quot;">​</a></h1><p>Bagisto implements a multi-layered caching strategy to optimize performance across the storefront, admin panel, and data access layers. Understanding these layers helps you build performant custom packages and debug cache-related issues.</p><h2 id="cache-layers-overview" tabindex="-1">Cache Layers Overview <a class="header-anchor" href="#cache-layers-overview" aria-label="Permalink to &quot;Cache Layers Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Technology</th><th>Scope</th><th>Configuration</th></tr></thead><tbody><tr><td><strong>Application Cache</strong></td><td>File / Redis / Memcached</td><td>Key-value storage for config, routes</td><td><code>CACHE_STORE</code> in <code>.env</code></td></tr><tr><td><strong>Repository Cache</strong></td><td>Prettus L5 Repository</td><td>Automatic model query caching</td><td><code>config/repository.php</code></td></tr><tr><td><strong>Full Page Cache (FPC)</strong></td><td>Spatie ResponseCache</td><td>Caches entire HTTP responses</td><td><code>RESPONSE_CACHE_ENABLED</code> in <code>.env</code></td></tr><tr><td><strong>Elasticsearch</strong></td><td>Elasticsearch 7.17+</td><td>Product search index</td><td><code>config/elasticsearch.php</code></td></tr><tr><td><strong>Session Store</strong></td><td>Database / Redis</td><td>User session data</td><td><code>SESSION_DRIVER</code> in <code>.env</code></td></tr></tbody></table><h2 id="application-cache" tabindex="-1">Application Cache <a class="header-anchor" href="#application-cache" aria-label="Permalink to &quot;Application Cache&quot;">​</a></h2><p>Configured via the <code>CACHE_STORE</code> environment variable. Default is <code>file</code>:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># .env</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CACHE_STORE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=file</span></span></code></pre></div><p>For production, Redis is recommended:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CACHE_STORE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=redis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">REDIS_HOST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=127.0.0.1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">REDIS_PORT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=6379</span></span></code></pre></div><p>Clear the application cache:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:clear</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or clear everything at once</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> optimize:clear</span></span></code></pre></div><h2 id="repository-cache" tabindex="-1">Repository Cache <a class="header-anchor" href="#repository-cache" aria-label="Permalink to &quot;Repository Cache&quot;">​</a></h2><p>Bagisto uses the <a href="https://github.com/prettus/l5-repository" target="_blank" rel="noreferrer">Prettus L5 Repository</a> package, which provides automatic query-level caching for repository operations. Configuration is in <code>config/repository.php</code>.</p><h3 id="automatic-invalidation" tabindex="-1">Automatic Invalidation <a class="header-anchor" href="#automatic-invalidation" aria-label="Permalink to &quot;Automatic Invalidation&quot;">​</a></h3><p>The <code>Webkul\\Core\\Listeners\\CleanCacheRepository</code> listener automatically invalidates cached repository data when entities are created, updated, or deleted:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Event: RepositoryEntityCreated → Cache cleared for that repository</span></span>
<span class="line"><span>Event: RepositoryEntityUpdated → Cache cleared for that repository</span></span>
<span class="line"><span>Event: RepositoryEntityDeleted → Cache cleared for that repository</span></span></code></pre></div><p>This is registered in <code>Webkul\\Core\\Providers\\EventServiceProvider</code> and runs globally for all repositories.</p><div class="tip custom-block"><p class="custom-block-title">No Manual Cache Clearing Needed</p><p>When you use the repository pattern (as Bagisto recommends), cache invalidation happens automatically. You don&#39;t need to manually clear caches after CRUD operations through repositories.</p></div><h2 id="full-page-cache-fpc" tabindex="-1">Full Page Cache (FPC) <a class="header-anchor" href="#full-page-cache-fpc" aria-label="Permalink to &quot;Full Page Cache (FPC)&quot;">​</a></h2><p>The FPC package (<code>Webkul\\FPC</code>) uses <a href="https://github.com/spatie/laravel-responsecache" target="_blank" rel="noreferrer">Spatie ResponseCache</a> to cache complete HTTP responses for storefront pages.</p><h3 id="enabling-fpc" tabindex="-1">Enabling FPC <a class="header-anchor" href="#enabling-fpc" aria-label="Permalink to &quot;Enabling FPC&quot;">​</a></h3><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># .env</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RESPONSE_CACHE_ENABLED</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span></code></pre></div><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><p>The <code>CacheResponse</code> middleware in the Shop package caches GET responses for guest users. When content changes, event listeners automatically invalidate affected URLs:</p><table tabindex="0"><thead><tr><th>Event</th><th>What Gets Invalidated</th></tr></thead><tbody><tr><td>Product create/update/delete</td><td>Product page URL + category pages</td></tr><tr><td>Category update/delete</td><td>Category page URL</td></tr><tr><td>Review update/delete</td><td>Corresponding product page</td></tr><tr><td>Order placed / Refund issued</td><td>Product pages (stock changes)</td></tr><tr><td>CMS page update/delete</td><td>CMS page URL</td></tr><tr><td>URL rewrite change</td><td>Old and new URLs</td></tr><tr><td>Theme customization change</td><td>Full cache clear</td></tr><tr><td>Core configuration change</td><td>Full cache clear</td></tr><tr><td>Channel update</td><td>Full cache clear</td></tr></tbody></table><h3 id="fpc-event-listeners" tabindex="-1">FPC Event Listeners <a class="header-anchor" href="#fpc-event-listeners" aria-label="Permalink to &quot;FPC Event Listeners&quot;">​</a></h3><p>These listeners are in <code>packages/Webkul/FPC/src/Listeners/</code> and are registered via <code>Webkul\\FPC\\Providers\\EventServiceProvider</code>:</p><ul><li><code>Product.php</code> — Invalidates product and category URLs</li><li><code>Category.php</code> — Invalidates category URLs</li><li><code>Review.php</code> — Invalidates reviewed product URLs</li><li><code>Order.php</code> — Invalidates product URLs for ordered items</li><li><code>Refund.php</code> — Invalidates product URLs for refunded items</li><li><code>Page.php</code> — Invalidates CMS page URLs</li><li><code>URLRewrite.php</code> — Invalidates rewritten URLs</li><li><code>ThemeCustomization.php</code> — Clears entire cache or specific URLs</li><li><code>CoreConfig.php</code> — Clears entire response cache</li></ul><div class="warning custom-block"><p class="custom-block-title">Admin Panel</p><p>The admin panel is explicitly excluded from response caching via the <code>NoCacheMiddleware</code> applied to all admin routes. This ensures admin users always see fresh data.</p></div><h2 id="cache-in-custom-packages" tabindex="-1">Cache in Custom Packages <a class="header-anchor" href="#cache-in-custom-packages" aria-label="Permalink to &quot;Cache in Custom Packages&quot;">​</a></h2><p>When building custom packages that modify data visible on the storefront, make sure to invalidate FPC for affected URLs:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Spatie\\ResponseCache\\Facades\\ResponseCache</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Clear specific URLs</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ResponseCache</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">forget</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;/products/my-product&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Clear everything</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ResponseCache</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span></code></pre></div><p>For repository-level cache, simply using the repository pattern ensures automatic invalidation. If you bypass the repository and use Eloquent directly, cached data may become stale.</p><h2 id="cache-configuration-for-production" tabindex="-1">Cache Configuration for Production <a class="header-anchor" href="#cache-configuration-for-production" aria-label="Permalink to &quot;Cache Configuration for Production&quot;">​</a></h2><p>Recommended <code>.env</code> settings for production:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CACHE_STORE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=redis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SESSION_DRIVER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=redis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">QUEUE_CONNECTION</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=redis</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RESPONSE_CACHE_ENABLED</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">REDIS_HOST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=127.0.0.1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">REDIS_PORT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=6379</span></span></code></pre></div><p>Run these commands after deployment:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config:cache</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route:cache</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> view:cache</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> event:cache</span></span></code></pre></div><p>To clear all caches at once:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> optimize:clear</span></span></code></pre></div>`,40)]))}const g=a(n,[["render",p]]);export{k as __pageData,g as default};
